#!/usr/bin/env python3
"""
setup.py — rust-inla project scaffold
======================================
Crea toda la estructura del proyecto en el directorio actual.

Uso (en el terminal de GitHub Codespaces):
    python3 setup.py

El script crea todos los archivos fuente y verifica que el proyecto compila.
"""
import pathlib, json, subprocess, sys

# Contenido de todos los archivos del proyecto (embebido en el script)
FILES = json.loads('''
{
  "Cargo.toml": "[package]\nname    = \"rust-inla\"\nversion = \"0.1.0\"\nedition = \"2021\"\n\n# ── Dependencias de producción ───────────────────────────────────────────────\n[dependencies]\n\n# Álgebra lineal sparse. NOTA: API de 0.19 cambió completamente en 0.24.\n# Cambios clave: try_new_from_triplets, row_idx_of_col_raw, val_of_col,\n# self_adjoint_eigen devuelve Result.\nfaer     = \"0.24.0\"\n\n# NOTA: faer-ext 0.7.1 (última versión) depende de faer=\"0.23.0\" —\n# incompatible con 0.24.0. Se añade en Fase D cuando exista versión\n# compatible, o se escribe la conversión faer→ndarray manualmente.\n\n# Paralelismo (equivalente a OpenMP del C backend).\nrayon = \"1.10\"\n\n# BFGS para optimización de hiperparámetros θ.\n# Equivalente al domin-interface.h/c original (bfgs3/bfgs4).\nargmin      = \"0.10\"\nargmin-math = \"0.4\"\n\n# Distribuciones estadísticas (equivalente a GSL del C backend).\nstatrs = \"0.18\"\n\n# Hash del grafo para caché de reorderings AMD.\nsha2 = \"0.10\"\n\n# Muestreo (necesario en density/ para SCGAUSSIAN).\nrand = \"0.8\"\n\n# Manejo de errores ergonómico. Lección aprendida de SMuRF.\nthiserror = \"2.0\"\n\n# Formato de intercambio para resultados → PyO3/extendr.\n# El feature \"approx\" habilita assert_abs_diff_eq! en tests.\nndarray = { version = \"0.16\", features = [\"approx\"] }\n# NOTA: el roadmap dice 0.17, pero 0.16 es la última estable en crates.io.\n# Actualizar a 0.17 cuando se publique.\n\n# ── Dependencias de desarrollo (tests y benchmarks) ──────────────────────────\n[dev-dependencies]\n\n# Para cargar los fixtures JSON contra R-INLA.\nserde      = { version = \"1\", features = [\"derive\"] }\nserde_json = \"1\"\n\n# assert_abs_diff_eq! con tolerancias — para validar contra fixtures.\napprox = \"0.5\"\n\n# Benchmarks de rendimiento (Fase A.5).\ncriterion = { version = \"0.5\", features = [\"html_reports\"] }\n\n[[bench]]\nname    = \"cholesky_bench\"\nharness = false\n",
  ".gitignore": "# Directorio de compilación — puede pesar varios GB con faer compilado.\n# NUNCA se sube a GitHub.\n/target/\n\n# Cargo.lock SÍ se sube en aplicaciones binarias, pero en librerías es opcional.\n# Lo incluimos para reproducibilidad exacta en CI.\n# (no lo ignoramos)\n",
  "src/lib.rs": "//! # rust-inla\n//!\n//! Port de R-INLA a Rust puro. Inferencia Bayesiana Aproximada para modelos\n//! de campo aleatorio gaussiano de Markov (GMRF) vía el algoritmo INLA.\n//!\n//! ## Arquitectura de módulos\n//!\n//! ```text\n//! inference/   ← InlaEngine::run() — integra todo\n//!   ├── optimizer/   ← BFGS sobre θ (argmin)\n//!   ├── problem/     ← constructor central: μ, log|Q|, Q⁻¹\n//!   │    ├── graph/      ← dispersidad de Q + patrón de L\n//!   │    ├── models/     ← trait QFunc: iid, rw1, rw2, ar1\n//!   │    └── solver/     ← Cholesky faer + selected inverse\n//!   ├── likelihood/  ← trait LogLikelihood: Gaussian, Poisson, Gamma...\n//!   ├── integrator/  ← Gauss-Kronrod 15pts\n//!   ├── density/     ← Gaussian / SCGAUSSIAN\n//!   └── marginal/    ← zmarginal, emarginal, tmarginal\n//! ```\n//!\n//! ## Estado de implementación\n//!\n//! Fase 0 (fixtures R-INLA): ✓ completa\n//! Fase A (core): en progreso\n//! Fase B (inference): pendiente\n\n// ── Módulos públicos ──────────────────────────────────────────────────────────\n\npub mod error;\npub mod graph;\npub mod likelihood;\npub mod models;\npub mod solver;\n\n// Módulos con implementación pendiente (stubs vacíos por ahora)\npub mod density;\npub mod inference;\npub mod integrator;\npub mod marginal;\npub mod optimizer;\npub mod problem;\n\n// ── Re-exportaciones de conveniencia ─────────────────────────────────────────\n\npub use error::InlaError;\npub use graph::Graph;\npub use likelihood::{LinkFunction, LogLikelihood};\npub use models::QFunc;\npub use solver::{SpIdx, SpMat, SparseSolver};\n",
  "src/error.rs": "//! Tipo de error central de rust-inla.\n//!\n//! Todos los módulos devuelven `Result<T, InlaError>`. Usar un único tipo\n//! de error evita el anti-patrón de `Box<dyn Error>` en boundaries de módulo\n//! y hace que el manejo de errores sea exhaustivo.\n\n/// Errores que puede producir cualquier operación de rust-inla.\n#[derive(Debug, thiserror::Error)]\npub enum InlaError {\n    // ── Solver ────────────────────────────────────────────────────────────────\n    /// Q no es definida positiva. Ocurre si θ está fuera del dominio válido\n    /// o si hay una inconsistencia numérica en QFunc::eval.\n    #[error(\"Cholesky failed: Q is not positive definite (theta may be out of range)\")]\n    NotPositiveDefinite,\n\n    /// Se llamó log_determinant / solve_llt / selected_inverse antes de\n    /// factorize(). El solver requiere el orden: reorder → build → factorize.\n    #[error(\"Solver not initialized — call reorder(), build(), factorize() in order\")]\n    SolverNotInitialized,\n\n    // ── Optimizador ──────────────────────────────────────────────────────────\n    /// BFGS no convergió dentro del límite de evaluaciones.\n    #[error(\"BFGS did not converge: {reason}\")]\n    ConvergenceFailed { reason: String },\n\n    // ── Fixtures / IO (solo tests) ────────────────────────────────────────────\n    /// Error al leer o parsear un fixture JSON de referencia.\n    #[error(\"Fixture error: {0}\")]\n    Fixture(String),\n\n    // ── Dimensiones ──────────────────────────────────────────────────────────\n    /// Incompatibilidad de tamaños entre estructuras.\n    #[error(\"Dimension mismatch: expected {expected}, got {got}\")]\n    DimensionMismatch { expected: usize, got: usize },\n}\n",
  "src/graph/mod.rs": "//! Estructura de dispersidad del campo aleatorio Q.\n//!\n//! `Graph` codifica qué pares (i,j) tienen entradas no-nulas en la matriz\n//! de precisión Q. Es el equivalente Rust de `graph.c` (2127 líneas).\n//!\n//! ## Responsabilidades de Graph\n//!\n//! 1. **Patrón de Q** — vecinos de cada nodo (CSC o lista de adyacencia).\n//!    Usado por `QFunc::eval` para saber qué entradas evaluar.\n//!\n//! 2. **Patrón de llenado de L** (post-reordering AMD).\n//!    Calculado por Cholesky simbólico. Usado por `selected_inverse`.\n//!    IMPORTANTE: este patrón puede ser más denso que el de Q.\n//!\n//! 3. **Hash SHA-2** del grafo de Q, para invalidar/reutilizar el caché\n//!    de reorderings entre evaluaciones de BFGS.\n//!\n//! ## Por qué guardar el patrón de L aquí\n//!\n//! En INLA, la inversa seleccionada Q⁻¹ se evalúa SOLO en las entradas\n//! (i,j) del patrón de L (no de Q). Si Graph no expone ese patrón,\n//! el solver no sabe sobre qué entradas iterar. Diseñar esto bien en A.1\n//! evita reescribir Graph en A.3 (cuando implementemos selected_inverse).\n\nuse sha2::{Digest, Sha256};\n\n/// Grafo de dispersidad de Q.\n///\n/// Fase A.1 implementa los constructores y el hash.\n/// Fase A.3 añade `fill_pattern` (patrón de L post-AMD).\n#[derive(Debug, Clone)]\npub struct Graph {\n    /// Número de nodos (= dimensión de Q).\n    pub n: usize,\n\n    /// Lista de adyacencia: `neighbors[i]` contiene los índices j > i\n    /// con Q(i,j) ≠ 0 (solo triangular superior, la diagonal se omite).\n    ///\n    /// Por convención, los vecinos están ordenados ascendentemente.\n    /// Esto es equivalente al `adjacency` de GMRFLib.\n    pub(crate) neighbors: Vec<Vec<usize>>,\n\n    /// Patrón de llenado de L después del reordering AMD.\n    /// `fill_pattern[i]` = índices j en la columna i de L (j ≥ i).\n    ///\n    /// Poblado por `FaerSolver::reorder()`. Vacío hasta entonces.\n    /// Fase A.3 lo completa.\n    pub(crate) fill_pattern: Vec<Vec<usize>>,\n\n    /// SHA-256 del patrón de Q. Se calcula una vez en el constructor.\n    /// `FaerSolver` lo compara con el hash cacheado para reutilizar\n    /// el reordering AMD sin recomputarlo.\n    pub(crate) graph_hash: [u8; 32],\n}\n\nimpl Graph {\n    /// Número de nodos del grafo.\n    #[inline]\n    pub fn n(&self) -> usize {\n        self.n\n    }\n\n    /// ¿Son i y j vecinos en Q? (i ≠ j, sin importar el orden)\n    pub fn are_neighbors(&self, i: usize, j: usize) -> bool {\n        let (lo, hi) = if i < j { (i, j) } else { (j, i) };\n        self.neighbors[lo].binary_search(&hi).is_ok()\n    }\n\n    /// Número total de entradas no-nulas en Q (incluyendo diagonal).\n    /// nnz(Q) = n + 2 * Σ|neighbors[i]|\n    pub fn nnz(&self) -> usize {\n        let off_diag: usize = self.neighbors.iter().map(|v| v.len()).sum();\n        self.n + 2 * off_diag\n    }\n\n    /// Hash del patrón de Q para caché de reorderings.\n    pub fn hash(&self) -> &[u8; 32] {\n        &self.graph_hash\n    }\n\n    // ── Constructores (Fase A.1) ──────────────────────────────────────────────\n\n    /// Grafo vacío (sin aristas). Equivale a modelo iid: Q diagonal.\n    /// Cada nodo es su propio vecino solo en la diagonal.\n    pub fn empty(n: usize) -> Self {\n        let neighbors = vec![vec![]; n];\n        let hash = Self::compute_hash(&neighbors, n);\n        Self {\n            n,\n            neighbors,\n            fill_pattern: vec![],\n            graph_hash: hash,\n        }\n    }\n\n    /// Grafo lineal (cadena): nodo i conectado a i+1.\n    /// Patrón de Q para RW1, RW2 (tridiagonal).\n    pub fn linear(n: usize) -> Self {\n        let mut neighbors = vec![vec![]; n];\n        for i in 0..n.saturating_sub(1) {\n            neighbors[i].push(i + 1);\n        }\n        let hash = Self::compute_hash(&neighbors, n);\n        Self {\n            n,\n            neighbors,\n            fill_pattern: vec![],\n            graph_hash: hash,\n        }\n    }\n\n    // ── Internals ─────────────────────────────────────────────────────────────\n\n    fn compute_hash(neighbors: &[Vec<usize>], n: usize) -> [u8; 32] {\n        let mut hasher = Sha256::new();\n        hasher.update(n.to_le_bytes());\n        for (i, nbrs) in neighbors.iter().enumerate() {\n            hasher.update(i.to_le_bytes());\n            for &j in nbrs {\n                hasher.update(j.to_le_bytes());\n            }\n            // Separador entre nodos para evitar colisiones de concatenación.\n            hasher.update([0xFF]);\n        }\n        hasher.finalize().into()\n    }\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn empty_graph_has_no_edges() {\n        let g = Graph::empty(5);\n        assert_eq!(g.n(), 5);\n        assert_eq!(g.nnz(), 5); // solo diagonal\n        for i in 0..5 {\n            for j in 0..5 {\n                if i != j {\n                    assert!(!g.are_neighbors(i, j));\n                }\n            }\n        }\n    }\n\n    #[test]\n    fn linear_graph_has_chain_edges() {\n        let g = Graph::linear(5);\n        assert!(g.are_neighbors(0, 1));\n        assert!(g.are_neighbors(1, 2));\n        assert!(g.are_neighbors(2, 3));\n        assert!(g.are_neighbors(3, 4));\n        assert!(!g.are_neighbors(0, 2)); // no hay aristas largas\n        // nnz = 5 (diag) + 2*4 (off-diag simétrico) = 13\n        assert_eq!(g.nnz(), 13);\n    }\n\n    #[test]\n    fn hash_changes_with_structure() {\n        let g1 = Graph::empty(5);\n        let g2 = Graph::linear(5);\n        assert_ne!(g1.hash(), g2.hash());\n    }\n\n    #[test]\n    fn hash_is_stable() {\n        let g1 = Graph::linear(10);\n        let g2 = Graph::linear(10);\n        assert_eq!(g1.hash(), g2.hash());\n    }\n}\n",
  "src/models/mod.rs": "//! Modelos de campo aleatorio gaussiano de Markov (GMRF).\n//!\n//! Equivalente Rust de `hgmrfm.h/c` y la sección de modelos latentes\n//! de `models.R`.\n//!\n//! ## Contrato: trait `QFunc`\n//!\n//! Cada modelo latente implementa `QFunc`. El trait define dos cosas:\n//! - La **estructura** del grafo de dispersidad (fija, independiente de θ)\n//! - La **evaluación** de la entrada (i,j) de Q en función de θ\n//!\n//! ## Por qué `graph()` no recibe `theta`\n//!\n//! En todos los modelos estándar (iid, RW1, RW2, AR1), el patrón de\n//! dispersidad de Q no cambia con los hiperparámetros θ. Solo cambian\n//! los *valores* de las entradas. Si `graph` dependiera de θ:\n//!\n//! - El hash del grafo cambiaría en cada evaluación de BFGS\n//! - El caché de reorderings AMD se invalidaría constantemente\n//! - Performance: O(n·log n) de AMD en cada llamada a f(θ)\n//!\n//! Si en el futuro existe un modelo con grafo dinámico, necesita un\n//! trait diferente — no una extensión de este.\n//!\n//! ## Orden de evaluación esperado por Problem\n//!\n//! ```text\n//! // Una sola vez por modelo:\n//! let g = qfunc.graph();\n//! solver.reorder(g);          // AMD — O(n·log n)\n//!\n//! // En cada evaluación de f(θ) dentro de BFGS:\n//! solver.build(g, &qfunc, theta);   // rellena valores de Q — O(nnz)\n//! solver.factorize()?;              // Cholesky — O(nnz(L))\n//! let log_det = solver.log_determinant();\n//! ```\n\nuse crate::graph::Graph;\n\n/// Contrato de cada modelo GMRF latente.\n///\n/// Los implementadores definen la estructura dispersa de Q y cómo\n/// evaluar cada entrada en función de los hiperparámetros θ.\npub trait QFunc: Send + Sync {\n    /// Grafo de dispersidad de Q.\n    ///\n    /// La referencia es `'static` en la práctica (el modelo posee el grafo),\n    /// pero el lifetime está ligado a `&self` para evitar `unsafe`.\n    ///\n    /// **Garantía**: el grafo no cambia durante la vida del modelo.\n    /// Si necesitas un grafo que cambia con θ, implementa un trait distinto.\n    fn graph(&self) -> &Graph;\n\n    /// Evalúa la entrada Q(i, j) para los hiperparámetros `theta`.\n    ///\n    /// - Solo se llama para pares (i,j) que son vecinos en `graph()`\n    ///   (o la diagonal, i == j).\n    /// - Debe ser **simétrica**: eval(i,j,θ) == eval(j,i,θ).\n    /// - `theta.len()` == `n_hyperparams()`.\n    ///\n    /// # Panics\n    /// No debe hacer panic. Si θ está fuera de rango, devuelve `f64::INFINITY`\n    /// para señalar al optimizador que ese punto no es válido.\n    fn eval(&self, i: usize, j: usize, theta: &[f64]) -> f64;\n\n    /// Número de hiperparámetros θ de este modelo.\n    ///\n    /// - iid:  1 (log-precisión τ)\n    /// - RW1:  1 (log-precisión de las diferencias)\n    /// - RW2:  1 (idem, orden 2)\n    /// - AR1:  2 (log-precisión marginal, arctanh(ρ))\n    fn n_hyperparams(&self) -> usize;\n}\n\n// ── Implementaciones (Fase A.2) ───────────────────────────────────────────────\n// Las structs concretas se añaden en Fase A.2:\n//   - IidModel\n//   - Rw1Model\n//   - Rw2Model\n//   - Ar1Model\n",
  "src/solver/mod.rs": "//! Solver disperso de Cholesky para la matriz de precisión Q.\n//!\n//! Equivalente Rust de `smtp-taucs.c` + `sparse-interface.h`.\n//!\n//! ## El algoritmo en tres fases\n//!\n//! ```text\n//! 1. reorder(graph)\n//!    └── AMD sobre el patrón de Q → permutación P\n//!    └── Cholesky simbólico → patrón de llenado de L\n//!    └── Almacena P y el patrón (caché por hash del grafo)\n//!\n//! 2. build(graph, qfunc, theta)\n//!    └── Evalúa QFunc::eval(i,j,theta) para cada (i,j) en el patrón\n//!    └── Rellena la matriz numérica Q en orden CSC reordenado\n//!\n//! 3. factorize()\n//!    └── Cholesky numérico: Q = L Lᵀ\n//!    └── log|Q| = 2 · Σ log(diag(L))    ← gratis de la factorización\n//!\n//! 4. [opcional] selected_inverse()\n//!    └── Algoritmo de inversa seleccionada (Takahashi et al.)\n//!    └── Calcula Q⁻¹ SOLO en el patrón de L  ← el corazón de INLA\n//! ```\n//!\n//! ## Por qué `selected_inverse` devuelve `SparseColMat` (no `&mut Problem`)\n//!\n//! El diseño original del CONTEXT.md tenía `compute_qinv(&mut Problem)`,\n//! lo que crea un ciclo de dependencias: solver/ → problem/ y problem/ → solver/.\n//!\n//! La solución: el solver devuelve la matriz Q⁻¹ (solo el patrón de L),\n//! y Problem la almacena. Dependencia unidireccional:\n//!\n//! ```text\n//! problem/ → solver/   ✓  (Problem llama al solver)\n//! solver/              ✓  (solver no conoce Problem)\n//! ```\n//!\n//! ## Alias de tipos para faer 0.24\n//!\n//! Centralizamos aquí para cambiar el índice (usize → u32 para matrices\n//! grandes) en un solo lugar cuando hagamos profiling.\n\nuse faer::sparse::SparseColMat;\n\nuse crate::error::InlaError;\nuse crate::graph::Graph;\nuse crate::models::QFunc;\n\n/// Tipo de índice para matrices sparse. `usize` es conservador;\n/// cambiar a `u32` reduce memoria a la mitad para n < 4B.\npub type SpIdx = usize;\n\n/// Matriz sparse CSC de f64 con índice `SpIdx`.\n/// Tipo de retorno de `selected_inverse`.\npub type SpMat = SparseColMat<SpIdx, f64>;\n\n/// Contrato del solver de Cholesky disperso.\n///\n/// La implementación concreta `FaerSolver` (Fase A.3) usa faer 0.24.\n/// El trait existe para desacoplar `Problem` de la implementación específica.\npub trait SparseSolver {\n    // ── Fase de setup (una sola vez por grafo) ────────────────────────────────\n\n    /// Calcula el reordering AMD y el patrón de llenado de L (Cholesky simbólico).\n    ///\n    /// Debe llamarse **una sola vez** por grafo distinto.\n    /// Si el hash del grafo ya está en caché, reutiliza el reordering.\n    ///\n    /// Efecto secundario: puebla `graph.fill_pattern` con el patrón de L.\n    fn reorder(&mut self, graph: &mut Graph);\n\n    // ── Fase numérica (una vez por evaluación de f(θ) en BFGS) ───────────────\n\n    /// Evalúa Q(θ) y la almacena en formato CSC reordenado.\n    ///\n    /// Precondición: `reorder` ya fue llamado con el mismo grafo.\n    /// Si no, el comportamiento es indefinido (posiblemente panic en debug).\n    fn build(&mut self, graph: &Graph, qfunc: &dyn QFunc, theta: &[f64]);\n\n    /// Factorización numérica de Cholesky: Q = L Lᵀ.\n    ///\n    /// # Errors\n    /// Devuelve `InlaError::NotPositiveDefinite` si Q no es PD.\n    /// Esto ocurre normalmente durante BFGS cuando θ está fuera del dominio;\n    /// el optimizador debe tratar este error como \"f(θ) = +∞\".\n    fn factorize(&mut self) -> Result<(), InlaError>;\n\n    // ── Resultados (tras factorize exitoso) ───────────────────────────────────\n\n    /// log|Q| = 2 · Σᵢ log(Lᵢᵢ).\n    ///\n    /// Gratis de la factorización — no hay costo adicional.\n    ///\n    /// # Panics (debug)\n    /// Si `factorize` no fue llamado antes.\n    fn log_determinant(&self) -> f64;\n\n    /// Resuelve Q·x = b en el espacio reordenado.\n    ///\n    /// Operación: b ← L⁻ᵀ L⁻¹ b (forward + backward substitution).\n    /// El resultado se escribe in-place en `rhs`.\n    ///\n    /// # Panics (debug)\n    /// Si `factorize` no fue llamado antes.\n    fn solve_llt(&self, rhs: &mut [f64]);\n\n    /// Inversa seleccionada: Q⁻¹ evaluada en el patrón de L.\n    ///\n    /// Implementa el algoritmo de Takahashi-Fagan-Chin (1973), también\n    /// conocido como \"supernodal selected inversion\" en el contexto de INLA.\n    ///\n    /// **Solo calcula las entradas (i,j) con L(i,j) ≠ 0.**\n    /// Las entradas fuera del patrón son cero en Q pero no en Q⁻¹;\n    /// INLA las ignora porque solo necesita las varianzas marginales\n    /// (diagonal) y covarianzas locales.\n    ///\n    /// # Por qué `&mut self`\n    /// El algoritmo modifica L in-place durante el cálculo.\n    /// La factorización Cholesky no es reutilizable después de esta llamada.\n    ///\n    /// # Errors\n    /// `InlaError::SolverNotInitialized` si no se llamó `factorize` antes.\n    fn selected_inverse(&mut self) -> Result<SpMat, InlaError>;\n}\n\n// ── Implementación concreta (Fase A.3) ────────────────────────────────────────\n// `FaerSolver` se añade en src/solver/faer_solver.rs en Fase A.3.\n",
  "src/likelihood/mod.rs": "//! Familias de verosimilitud p(y | η, θ).\n//!\n//! Equivalente Rust de la sección de likelihood de `models.R` e `inla.c`.\n//!\n//! ## Familias Fase B core\n//!\n//! | Familia    | Link    | Parámetros θ extra |\n//! |------------|---------|-------------------|\n//! | Gaussian   | identity| 1 (log-precisión) |\n//! | Poisson    | log     | 0                 |\n//! | Gamma      | log     | 1 (log-shape)     |\n//! | Binomial   | logit   | 0                 |\n//! | NegBinomial| log     | 1 (log-overdispersión) |\n//! | Beta       | logit   | 1 (log-precisión) |\n\n/// Función de enlace η → μ (o μ → η en la dirección inversa).\n#[derive(Debug, Clone, Copy, PartialEq, Eq)]\npub enum LinkFunction {\n    /// μ = η (Gaussian)\n    Identity,\n    /// μ = exp(η) (Poisson, Gamma, NegBinomial)\n    Log,\n    /// μ = 1/(1+exp(-η)) (Binomial, Beta)\n    Logit,\n}\n\nimpl LinkFunction {\n    /// Aplica la función de enlace inversa: η → μ.\n    #[inline]\n    pub fn inverse(&self, eta: f64) -> f64 {\n        match self {\n            LinkFunction::Identity => eta,\n            LinkFunction::Log     => eta.exp(),\n            LinkFunction::Logit   => 1.0 / (1.0 + (-eta).exp()),\n        }\n    }\n\n    /// Aplica la función de enlace directa: μ → η.\n    #[inline]\n    pub fn forward(&self, mu: f64) -> f64 {\n        match self {\n            LinkFunction::Identity => mu,\n            LinkFunction::Log     => mu.ln(),\n            LinkFunction::Logit   => (mu / (1.0 - mu)).ln(),\n        }\n    }\n}\n\n/// Contrato de cada familia de verosimilitud.\n///\n/// Equivalente al callback de likelihood en `approx-inference.h`.\npub trait LogLikelihood: Send + Sync {\n    /// Evalúa log p(yᵢ | ηᵢ, θ) para las observaciones en `y_slice`.\n    ///\n    /// # Argumentos\n    /// - `logll`  — slice de salida donde escribir log p(yᵢ | ηᵢ, θ)\n    /// - `eta`    — predictores lineales ηᵢ = xᵢ + βᵀzᵢ\n    /// - `y`      — observaciones correspondientes\n    /// - `theta`  — hiperparámetros de la likelihood (puede ser vacío)\n    ///\n    /// # Contrato\n    /// `logll.len() == eta.len() == y.len()`\n    fn evaluate(\n        &self,\n        logll: &mut [f64],\n        eta:   &[f64],\n        y:     &[f64],\n        theta: &[f64],\n    );\n\n    /// ¿Tiene derivadas analíticas? Si no, Problem usa diferencias finitas.\n    /// Por defecto: false (diferencias finitas, como R-INLA).\n    fn has_exact_derivatives(&self) -> bool {\n        false\n    }\n\n    /// Función de enlace de esta familia.\n    fn link(&self) -> LinkFunction;\n}\n\n// ── Implementaciones (Fase B.1) ───────────────────────────────────────────────\n// GaussianLikelihood, PoissonLikelihood, GammaLikelihood, etc.\n",
  "src/problem/mod.rs": "//! Constructor central: dado θ, produce μ y log|Q|.\n//!\n//! Equivalente Rust de `problem-setup.h/c` (2500 líneas).\n//!\n//! ## Responsabilidad de Problem\n//!\n//! Por cada evaluación de f(θ) dentro de BFGS:\n//!\n//! ```text\n//! Problem::eval(theta)\n//!   ├── solver.build(graph, qfunc, theta)   // rellena Q(θ)\n//!   ├── solver.factorize()                  // Q = LLᵀ\n//!   ├── log_det = solver.log_determinant()  // 2·Σlog(diag(L))\n//!   ├── mu = solver.solve_llt(b)            // media posterior\n//!   └── [si se necesita Qinv]\n//!       qinv = solver.selected_inverse()    // almacenado aquí\n//! ```\n//!\n//! Problem posee el `SpMat` de Q⁻¹ (devuelto por el solver),\n//! rompiendo la dependencia circular del diseño original.\n\n// Fase A.4: implementar Problem struct\n",
  "src/optimizer/mod.rs": "//! Optimización de hiperparámetros θ vía BFGS.\n//!\n//! Equivalente Rust de `domin-interface.h/c` (1596 líneas).\n//!\n//! Usa el crate `argmin` 0.10. La función objetivo es:\n//!   f(θ) = -log p(y|θ) = -log p(y|x,θ) - log p(x|θ) + cte\n//!\n//! El gradiente se calcula por diferencias finitas (igual que R-INLA).\n//! Cada evaluación de f(θ) ejecuta una factorización de Cholesky completa.\n\n// Fase B.2: implementar InlaOptimizer\n",
  "src/integrator/mod.rs": "//! Integración numérica Gauss-Kronrod de 15 puntos.\n//!\n//! Equivalente Rust de `integrator.c` (1054 líneas).\n//!\n//! Las constantes de cuadratura están hardcodeadas igual que en el C original.\n//! Se usan para integrar las densidades marginales sobre θ.\n\n// Fase B.3: implementar gauss_kronrod_15 con constantes hardcodeadas\n",
  "src/density/mod.rs": "//! Densidades marginales aproximadas.\n//!\n//! Equivalente Rust de `density.h/c` (2413 líneas).\n//!\n//! ## Tipos de densidad\n//!\n//! - `Density::Gaussian` — aproximación gaussiana simple\n//! - `Density::ScGaussian` — Gaussiana + corrección log-spline (default INLA)\n//!\n//! La densidad default de INLA es SCGAUSSIAN (Skew-Corrected Gaussian),\n//! que añade una corrección de asimetría a la aproximación Laplace.\n\n// Fase B.4: implementar enum Density { Gaussian, ScGaussian }\n",
  "src/marginal/mod.rs": "//! Transformaciones de densidades marginales.\n//!\n//! Equivalente Rust de `marginal.R` (567 líneas).\n//!\n//! Funciones: zmarginal, emarginal, tmarginal\n//! (equivalentes a inla.zmarginal, inla.emarginal, inla.tmarginal en R).\n\n// Fase B.5: implementar struct Marginal { x, y } + métodos\n",
  "src/inference/mod.rs": "//! Motor principal de inferencia INLA.\n//!\n//! Equivalente Rust de `approx-inference.h/c` (8725 líneas).\n//!\n//! `InlaEngine::run()` integra todos los módulos:\n//! Optimizer → Problem → Solver → Density → Marginal → InlaResult\n\n// Fase B.6: implementar InlaEngine, InlaResult, InlaModel, InlaParams\n",
  "benches/cholesky_bench.rs": "// Benchmark de rendimiento del solver de Cholesky.\n// Implementación completa en Fase A.5.\n//\n// Este archivo existe para satisfacer la declaración [[bench]] en Cargo.toml.\n// Criterion requiere un punto de entrada aunque el benchmark esté vacío.\n\nuse criterion::criterion_main;\n\n// En Fase A.5 se añadirá:\n// criterion_group!(benches, bench_cholesky_10k);\n// criterion_main!(benches);\n\n// Por ahora: punto de entrada vacío para que cargo build no falle.\ncriterion_main!();\n",
  ".github/workflows/ci.yml": "# Pipeline de CI para rust-inla.\n# Se ejecuta automáticamente en cada push y pull request.\n# Puedes ver los resultados en la pestaña \"Actions\" de tu repositorio en GitHub.\n\nname: CI\n\non:\n  push:\n    branches: [ \"main\" ]\n  pull_request:\n    branches: [ \"main\" ]\n\n# Un solo job por ahora. En Fase B añadiremos jobs separados para\n# tests de integración contra los fixtures R-INLA.\njobs:\n  build-and-test:\n    name: Build & Test\n    runs-on: ubuntu-latest\n\n    steps:\n      # 1. Descarga el código del repositorio en la máquina de GitHub.\n      - name: Checkout\n        uses: actions/checkout@v4\n\n      # 2. Instala Rust stable en la máquina de GitHub.\n      #    dtolnay/rust-toolchain es la forma estándar — más rápida que rustup manual.\n      - name: Install Rust\n        uses: dtolnay/rust-toolchain@stable\n        with:\n          # clippy: linter que detecta patrones problemáticos en Rust.\n          # rustfmt: formateador de código.\n          components: clippy, rustfmt\n\n      # 3. Cachea las dependencias compiladas entre runs.\n      #    Sin esto, cada push recompila faer + rayon + todas las deps (~3-5 min).\n      #    Con cache, solo recompila lo que cambió (~30 segundos).\n      - name: Cache cargo\n        uses: actions/cache@v4\n        with:\n          path: |\n            ~/.cargo/registry\n            ~/.cargo/git\n            target/\n          key: ${{ runner.os }}-cargo-${{ hashFiles('**/Cargo.lock') }}\n          restore-keys: |\n            ${{ runner.os }}-cargo-\n\n      # 4. Verifica que el código compila sin errores.\n      #    --locked: usa exactamente las versiones de Cargo.lock (reproducible).\n      - name: Build\n        run: cargo build --locked\n\n      # 5. Corre todos los tests unitarios (los #[test] que escribimos en cada módulo).\n      - name: Test\n        run: cargo test --locked\n\n      # 6. Clippy: linter de Rust. Más estricto que el compilador.\n      #    -D warnings: trata warnings como errores (no pasan en CI).\n      #    Esto mantiene el código limpio — si escribes algo que clippy no aprueba,\n      #    el CI falla y te avisa exactamente dónde y por qué.\n      - name: Clippy\n        run: cargo clippy --locked -- -D warnings\n\n      # 7. Verifica formato. Si el código no está formateado con rustfmt, falla.\n      #    En Codespaces esto no ocurre porque \"formatOnSave\" está activado.\n      - name: Format check\n        run: cargo fmt --check\n",
  "tests/fixtures/README.md": "# tests/fixtures/\n\nFixtures de referencia generados por R-INLA.\n\n## Archivos\n\n| Archivo | Descripción | Tolerancias |\n|---|---|---|\n| `iid_gaussian.json` | Modelo iid Gaussiano | log_mlik: 1e-4, mean_x: 1e-3 |\n| `rw1_poisson.json` | RW1 Poisson (frecuencia) | log_mlik: 1e-4, mean_x: 1e-3 |\n| `ar1_gamma.json` | AR1 Gamma (severidad) | log_mlik: 1e-4, mean_x: 1e-3 |\n| `cholesky_rw1.json` | Cholesky directo n=10,000 | log_det: 1e-8, sol: 1e-8 |\n\n## Cómo regenerar\n\n```bash\nRscript tests/fixtures/generate_fixtures.R\n```\n\nRequiere R con INLA instalado:\n```r\ninstall.packages(\"INLA\", repos = c(getOption(\"repos\"),\n  INLA = \"https://inla.r-inla-download.org/R/stable\"))\n```\n\n## Notas sobre los fixtures actuales\n\n- `cholesky_rw1.json`: generado con n=10,000 (no n=10 del script original).\n  Es un stress test de escala real. El log_det=2.399 es correcto para\n  Q = DᵀD + 1e-6·I con D la matriz de diferencias de orden 10,000.\n\n- `iid_gaussian.json`: generado con n≈500 (no n=50 del script original).\n"
}
''')

def main():
    print("\n🔧 Creando estructura del proyecto rust-inla...\n")
    
    created = 0
    for path_str, content in FILES.items():
        p = pathlib.Path(path_str)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_text(content, encoding="utf-8")
        print(f"  ✓ {path_str}")
        created += 1
    
    print(f"\n📁 {created} archivos creados.\n")
    print("🔨 Ejecutando cargo build (puede tardar 2-3 min la primera vez)...\n")
    
    result = subprocess.run(
        ["cargo", "build"],
        capture_output=True, text=True
    )
    
    if result.returncode == 0:
        print("  ✅ cargo build: OK")
    else:
        print("  ❌ cargo build falló:")
        print(result.stderr[-3000:])
        sys.exit(1)
    
    print("\n🧪 Ejecutando tests...\n")
    result2 = subprocess.run(
        ["cargo", "test"],
        capture_output=True, text=True
    )
    
    if result2.returncode == 0:
        print("  ✅ cargo test: OK")
        # Mostrar resumen de tests
        for line in result2.stdout.splitlines():
            if "test result" in line or "running" in line or "FAILED" in line:
                print(f"     {line}")
    else:
        print("  ❌ cargo test falló:")
        print(result2.stdout[-2000:])
        print(result2.stderr[-1000:])
        sys.exit(1)
    
    print("\n" + "="*50)
    print("✅ Proyecto listo. Próximos pasos:")
    print("")
    print("  git add .")
    print("  git commit -m \"feat: scaffold inicial rust-inla\"")
    print("  git push")
    print("="*50 + "\n")

if __name__ == "__main__":
    main()
